function googleToken() {
  var refreshToken;
  try { refreshToken = getVar('google_refresh_token'); } catch(e) {
    return {error: 'NOT_LOGGED_IN', message: 'You are not logged in to Google. Please use /login (Telegram) or !login (Discord) to connect your Google account first.'};
  }
  var resp = httpPost('https://oauth2.googleapis.com/token', 'client_id=' + encodeURIComponent(getVar('google_client_id')) + '&client_secret=' + encodeURIComponent(getVar('google_client_secret')) + '&refresh_token=' + encodeURIComponent(refreshToken) + '&grant_type=refresh_token', {'Content-Type': 'application/x-www-form-urlencoded'});
  var t = resp.body;
  if (t.error) throw new Error('token refresh failed: ' + t.error);
  return {token: t.access_token};
}
var auth = googleToken();
if (auth.error) return JSON.stringify(auth);
var token = auth.token;
var max = args.max_results || 10;
var timeMin = args.time_min || new Date().toISOString();
var url = 'https://www.googleapis.com/calendar/v3/calendars/primary/events?maxResults=' + max + '&timeMin=' + encodeURIComponent(timeMin) + '&singleEvents=true&orderBy=startTime';
if (args.time_max) url += '&timeMax=' + encodeURIComponent(args.time_max);
var resp = httpGet(url, {'Authorization': 'Bearer ' + token});
var body = resp.body;
var events = (body.items || []).map(function(e) {
  return {id: e.id, summary: e.summary || '', start: (e.start && (e.start.dateTime || e.start.date)) || '', end: (e.end && (e.end.dateTime || e.end.date)) || '', location: e.location || '', description: e.description || ''};
});
return JSON.stringify(events, null, 2);

function googleToken() {
  var refreshToken;
  try { refreshToken = getVar('google_refresh_token'); } catch(e) {
    return {error: 'NOT_LOGGED_IN', message: 'You are not logged in to Google. Please use /login (Telegram) or !login (Discord) to connect your Google account first.'};
  }
  var resp = httpPost('https://oauth2.googleapis.com/token', 'client_id=' + encodeURIComponent(getVar('google_client_id')) + '&client_secret=' + encodeURIComponent(getVar('google_client_secret')) + '&refresh_token=' + encodeURIComponent(refreshToken) + '&grant_type=refresh_token', {'Content-Type': 'application/x-www-form-urlencoded'});
  var t = resp.body;
  if (t.error) throw new Error('token refresh failed: ' + t.error);
  return {token: t.access_token};
}
var auth = googleToken();
if (auth.error) return JSON.stringify(auth);
var token = auth.token;
var event = {summary: args.summary, start: {dateTime: args.start}, end: {dateTime: args.end}};
if (args.description) event.description = args.description;
if (args.location) event.location = args.location;
var resp = httpPost('https://www.googleapis.com/calendar/v3/calendars/primary/events', JSON.stringify(event), {'Authorization': 'Bearer ' + token, 'Content-Type': 'application/json'});
return JSON.stringify(resp.body, null, 2);
